+using Microsoft.ML;
+using TicketClassifier.Models;
+
+namespace TicketClassifier.Services;
+
+public class ModelTrainerService
+{
+    private readonly MLContext _mlContext = new(seed: 42);
+    private readonly string _dataPath;
+    private readonly string _modelPath;
+    private readonly ILogger<ModelTrainerService> _logger;
+
+    public ModelTrainerService(ILogger<ModelTrainerService> logger, IWebHostEnvironment env)
+    {
+        _logger = logger;
+        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
+        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
+    }
+
+    public ModelMetrics TrainAndEvaluate()
+    {
+        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
+            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
+
+        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
+
+        var pipeline = _mlContext.Transforms.Conversion
+                .MapValueToKey("Label", nameof(TicketData.Category))
+            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
+            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
+            .Append(_mlContext.Transforms.Concatenate("Features",
+                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
+            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
+                labelColumnName: "Label", featureColumnName: "Features"))
+            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
+
+        _logger.LogInformation("Training model on {Path}...", _dataPath);
+        var model = pipeline.Fit(split.TrainSet);
+
+        var predictions = model.Transform(split.TestSet);
+        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");
+
+        _logger.LogInformation(
+            "Evaluation — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
+            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);
+
+        _mlContext.Model.Save(model, data.Schema, _modelPath);
+        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);
+
+        return new ModelMetrics(
+            metrics.MicroAccuracy,
+            metrics.MacroAccuracy,
+            metrics.LogLoss,
+            metrics.LogLossReduction,
+            metrics.ConfusionMatrix.GetFormattedConfusionTable());
+    }
+
+    public string ModelPath => _modelPath;
+}
+
+public record ModelMetrics(
+    double MicroAccuracy,
+    double MacroAccuracy,
+    double LogLoss,
+    double LogLossReduction,
+    string ConfusionMatrix);
+

