using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly ModelTrainerService _trainer;
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    public TicketClassifierController(
        ModelTrainerService trainer,
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _trainer = trainer;
        _predictionPool = predictionPool;
    }

    /// <summary>Trains the model and returns evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<ModelMetrics> Train()
    {
        var metrics = _trainer.TrainAndEvaluate();
        return Ok(metrics);
    }

    /// <summary>Predicts the category for a support ticket.</summary>
    [HttpPost("predict")]
    public ActionResult Predict([FromBody] TicketRequest request)
    {
        if (!System.IO.File.Exists(_trainer.ModelPath))
            return BadRequest("Model has not been trained yet. POST to /api/ticketclassifier/train first.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        return Ok(new
        {
            prediction.PredictedCategory,
            Confidence = prediction.Score.Max(),
            Scores = prediction.Score
        });
    }
}

public record TicketRequest(string Subject, string Description, int Priority);

